-- ============================================================
-- 백화점 리테일 (Department Store Retail)
-- 현대백화점 기본반 · 미니프로젝트 연습용 데이터셋 (MySQL)
-- ============================================================
SET NAMES utf8mb4;

SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS regions;
DROP TABLE IF EXISTS stores;
DROP TABLE IF EXISTS membership_grades;
DROP TABLE IF EXISTS categories;
DROP TABLE IF EXISTS brands;
DROP TABLE IF EXISTS suppliers;
DROP TABLE IF EXISTS products;
DROP TABLE IF EXISTS inventory;
DROP TABLE IF EXISTS employees;
DROP TABLE IF EXISTS members;
DROP TABLE IF EXISTS orders;
DROP TABLE IF EXISTS order_items;
DROP TABLE IF EXISTS payments;
DROP TABLE IF EXISTS reviews;
SET FOREIGN_KEY_CHECKS = 1;

CREATE TABLE regions (region_id INT PRIMARY KEY, region_name VARCHAR(20));


CREATE TABLE stores (store_id INT PRIMARY KEY, store_name VARCHAR(30), region_id INT, opened_date DATE);


CREATE TABLE membership_grades (grade_id INT PRIMARY KEY, grade_name VARCHAR(20), min_amount INT);


CREATE TABLE categories (category_id INT PRIMARY KEY, category_name VARCHAR(20));


CREATE TABLE brands (brand_id INT PRIMARY KEY, brand_name VARCHAR(30), tier INT);


CREATE TABLE suppliers (supplier_id INT PRIMARY KEY, supplier_name VARCHAR(30), city VARCHAR(20));


CREATE TABLE products (product_id INT PRIMARY KEY, product_name VARCHAR(40), category_id INT, brand_id INT, supplier_id INT, price INT);


CREATE TABLE inventory (inventory_id INT PRIMARY KEY, store_id INT, product_id INT, stock_qty INT);


CREATE TABLE employees (employee_id INT PRIMARY KEY, employee_name VARCHAR(20), store_id INT, role VARCHAR(20), hire_date DATE, salary INT);


CREATE TABLE members (member_id INT PRIMARY KEY, member_name VARCHAR(20), gender CHAR(1), grade_id INT, city VARCHAR(20), joined_date DATE);


CREATE TABLE orders (order_id INT PRIMARY KEY, member_id INT, store_id INT, employee_id INT, order_date DATE, total_amount INT);


CREATE TABLE order_items (item_id INT PRIMARY KEY, order_id INT, product_id INT, quantity INT, unit_price INT);


CREATE TABLE payments (order_id INT PRIMARY KEY, method VARCHAR(10), amount INT, paid_date DATE);


CREATE TABLE reviews (review_id INT PRIMARY KEY, product_id INT, member_id INT, rating INT, review_date DATE);

